  async getPromotionAnalytics(id) {
    await this._delay(400);
    const promo = PROMOTIONS.find((p2) => p2.id === id);
    if (!promo) throw new Error("Promotion not found");
    const days = 7;
    const dailyReach = Array.from({ length: days }, (_2, i) => {
      const date = new Date(Date.now() - (days - 1 - i) * 864e5);
      const reached = Math.floor(
        promo.usersReached / days * (0.8 + Math.random() * 0.4)
      );
      const viewed = Math.floor(reached * (0.5 + Math.random() * 0.4));
      return { date: date.toLocaleDateString("en-IN"), reached, viewed };
    });
    return {
      promotionId: id,
      title: promo.title,
      usersReached: promo.usersReached,
      usersViewed: promo.usersViewed,
      planUsersReach: promo.planUsersReach,
      reachRate: promo.planUsersReach > 0 ? Math.round(promo.usersReached / promo.planUsersReach * 100) : 0,
      viewRate: promo.usersReached > 0 ? Math.round(promo.usersViewed / promo.usersReached * 100) : 0,
      dailyReach
    };
  }
