function buildSeedSummaryMessage(s2) {
  const parts = [];
  if (s2.cities > 0) parts.push(`${s2.cities} cities`);
  if (s2.customers > 0) parts.push(`${s2.customers} customers`);
  if (s2.deliveryPartners > 0)
    parts.push(`${s2.deliveryPartners} delivery partners`);
  if (s2.merchants > 0) parts.push(`${s2.merchants} merchants`);
  if (s2.products > 0) parts.push(`${s2.products} products`);
  if (s2.jobs > 0) parts.push(`${s2.jobs} jobs`);
  if (s2.adhocJobs > 0) parts.push(`${s2.adhocJobs} adhoc jobs`);
  if (s2.properties > 0) parts.push(`${s2.properties} properties`);
  if (s2.oldItems > 0) parts.push(`${s2.oldItems} old items`);
  if (s2.recipes > 0) parts.push(`${s2.recipes} recipes`);
  if (s2.healthcareProviders > 0)
    parts.push(`${s2.healthcareProviders} healthcare providers`);
  if (s2.tourOperators > 0) parts.push(`${s2.tourOperators} tour operators`);
  if (s2.professionalServices > 0)
    parts.push(`${s2.professionalServices} professional services`);
  if (s2.supportTickets > 0) parts.push(`${s2.supportTickets} support tickets`);
  if (s2.events > 0) parts.push(`${s2.events} events`);
  if (s2.promotions > 0) parts.push(`${s2.promotions} promotions`);
  if (s2.shuttleRoutes > 0) parts.push(`${s2.shuttleRoutes} shuttle routes`);
  if (s2.donations > 0) parts.push(`${s2.donations} donations`);
  if (s2.subscriptionPlans > 0)
    parts.push(`${s2.subscriptionPlans} subscription plans`);
  if (s2.rateCards > 0) parts.push(`${s2.rateCards} rate cards`);
  if (s2.lendingItems > 0) parts.push(`${s2.lendingItems} lending items`);
  if (s2.communityMembers > 0)
    parts.push(`${s2.communityMembers} community members`);
  if (parts.length === 0) return "Sample data loaded successfully";
  return `Sample data loaded: ${parts.join(", ")}`;
}
