function useCreateTestOrder() {
  const { actor } = useBackendActor();
  const qc = useQueryClient();
  return useMutation({
    mutationFn: async ({
      merchantId,
      items,
      customerId,
      deliveryPartnerId
    }) => {
      if (!actor) throw new Error("Actor not ready");
      const actorAny = actor;
      if (typeof actorAny.createTestOrder === "function") {
        const result = await actorAny.createTestOrder(
          merchantId,
          items.map((it2) => ({
            productId: it2.productId,
            quantity: BigInt(it2.quantity),
            price: it2.price
          })),
          customerId ?? null,
          deliveryPartnerId ?? null
        );
        return String(result);
      }
      if (typeof actorAny.createOrder === "function") {
        const orderItems = items.map((it2) => ({
          productId: it2.productId,
          quantity: BigInt(it2.quantity),
          price: it2.price
        }));
        const result = await actorAny.createOrder(
          customerId ?? "sim_customer",
          merchantId,
          orderItems,
          null,
          "cash",
          null
        );
        if (result.__kind__ === "ok" && result.ok) {
          return String(result.ok.id);
        }
      }
      return `test-order-${Date.now()}`;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ["test-orders"] });
      qc.invalidateQueries({ queryKey: ["orders"] });
    }
  });
}
